<script>
import { nextTick } from "vue";
import * as THREE from "three";
import { GLTFLoader } from "three/examples/jsm/loaders/GLTFLoader.js";
import { OrbitControls } from "three/examples/jsm/controls/OrbitControls.js";

export default {
  name: "3DModelViewer",
  props: {
    glbModelUrl: {
      type: String,
      required: true,
    },
    Model_instance_id: {
      type: String,
      required: true,
    },
    isLoading: {
      type: Boolean,
      required: false,
      default: false,
    },
  },
  data() {
    return {
      loading: false,
      closeShareMenu: true,
      modelLoaded: false,
    };
  },
  created() {
    // Store Three.js objects outside of Vue's reactive system
    this.scene = null;
    this.camera = null;
    this.renderer = null;
    this.controls = null;
    this.animationId = null;
    this.backgroundScene = null;
    this.backgroundCamera = null;
    this.bgMesh = null;
    this.model = null;
    this.modelBoundingBox = null;
    this.modelCenter = null;
    this.modelSize = null;
  },
  watch: {
    glbModelUrl(newUrl, oldUrl) {
      if (newUrl && newUrl !== oldUrl) {
        this.loadModel();
      }
    },
  },
  mounted() {
    window.addEventListener("resize", this.onWindowResize);

    nextTick(() => {
      const container = this.$refs.viewer || this.$refs.canvasContainer;
      if (container) {
        this.initializeScene(container);
        this.initializeBackground();
        this.initializeLighting();
        this.initializeControls();

        if (this.glbModelUrl) {
          this.loadModel();
        }

        this.animate();
      }
    });
  },
  beforeUnmount() {
    if (this.animationId) {
      cancelAnimationFrame(this.animationId);
    }

    window.removeEventListener("resize", this.onWindowResize);

    if (this.renderer) {
      if (this.scene) {
        this.scene.traverse((child) => {
          if (child.geometry) child.geometry.dispose();
          if (child.material) {
            if (Array.isArray(child.material)) {
              child.material.forEach((material) => material.dispose());
            } else {
              child.material.dispose();
            }
          }
        });
      }
      this.renderer.dispose();
    }
  },
  methods: {
    initializeScene(container) {
      this.scene = new THREE.Scene();
      this.backgroundScene = new THREE.Scene();
      this.backgroundCamera = new THREE.Camera();

      const width = container.clientWidth || window.innerWidth;
      const height = this.glbModelUrl
        ? (container.clientHeight || window.innerHeight) - 170
        : container.clientHeight || window.innerHeight;

      this.camera = new THREE.PerspectiveCamera(45, width / height, 0.1, 1000);

      this.renderer = new THREE.WebGLRenderer({
        antialias: true,
        alpha: true,
      });
      this.renderer.setSize(width, height);
      this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
      this.renderer.outputColorSpace = THREE.SRGBColorSpace;
      this.renderer.shadowMap.enabled = true;
      this.renderer.shadowMap.type = THREE.PCFSoftShadowMap;
      this.renderer.setClearColor(0xf5f5f5, 1);

      while (container.firstChild) {
        container.removeChild(container.firstChild);
      }

      container.appendChild(this.renderer.domElement);
    },

    initializeBackground() {
      const canvas = document.createElement("canvas");
      canvas.width = 512;
      canvas.height = 512;
      const ctx = canvas.getContext("2d");

      const gradient = ctx.createLinearGradient(0, 0, 0, 512);
      gradient.addColorStop(0, "#f2f2f2");
      gradient.addColorStop(1, "#f2f2f2");
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, 512, 512);

      const backgroundTexture = new THREE.CanvasTexture(canvas);
      this.updateBackground(backgroundTexture);
    },

    updateBackground(texture) {
      texture.minFilter = THREE.LinearFilter;
      texture.magFilter = THREE.LinearFilter;
      texture.colorSpace = THREE.SRGBColorSpace;

      const bgGeo = new THREE.PlaneGeometry(2, 2);
      const bgMat = new THREE.MeshBasicMaterial({
        map: texture,
        depthTest: false,
      });

      if (this.bgMesh) this.backgroundScene.remove(this.bgMesh);

      this.bgMesh = new THREE.Mesh(bgGeo, bgMat);
      this.bgMesh.position.z = -1;
      this.backgroundScene.add(this.bgMesh);
    },

    initializeLighting() {
      // Soft ambient light for base illumination
      this.scene.add(new THREE.AmbientLight(0xffffff, 0.5));

      // Gentle hemisphere light for natural soft lighting
      const hemisphereLight = new THREE.HemisphereLight(
        0xe3f2fd,
        0xfce4ec,
        0.5
      );
      this.scene.add(hemisphereLight);

      // Soft main directional light
      const dirLight = new THREE.DirectionalLight(0xffffff, 3);
      dirLight.position.set(10, 15, 5);
      dirLight.castShadow = true;
      dirLight.shadow.mapSize.width = 2048;
      dirLight.shadow.mapSize.height = 2048;
      dirLight.shadow.camera.near = 0.1;
      dirLight.shadow.camera.far = 50;
      dirLight.shadow.camera.left = -20;
      dirLight.shadow.camera.right = 20;
      dirLight.shadow.camera.top = 20;
      dirLight.shadow.camera.bottom = -20;
      dirLight.shadow.bias = -0.001;
      this.scene.add(dirLight);

      // Soft fill light from opposite direction
      const fillLight = new THREE.DirectionalLight(0xfce4ec, 0.3);
      fillLight.position.set(-10, 5, -5);
      this.scene.add(fillLight);

      // Subtle accent light
      const accentLight = new THREE.DirectionalLight(0xe3f2fd, 0.2);
      accentLight.position.set(5, 10, 10);
      this.scene.add(accentLight);

      // Very subtle rim light
      const rimLight = new THREE.DirectionalLight(0xffffff, 0.2);
      rimLight.position.set(-5, 5, -10);
      this.scene.add(rimLight);
    },

    initializeControls() {
      this.controls = new OrbitControls(this.camera, this.renderer.domElement);
      this.controls.enableDamping = true;
      this.controls.dampingFactor = 0.1;
      this.controls.maxPolarAngle = Math.PI * 0.48;
      this.controls.minDistance = 1;
      this.controls.maxDistance = 20;

      this.camera.position.set(5, 5, 5);
      this.controls.target.set(0, 0, 0);
      this.controls.update();
    },

    loadModel() {
      if (!this.glbModelUrl || !this.scene) return;

      this.loading = true;
      this.modelLoaded = false;

      // Clear ALL objects from scene (except lights)
      const objectsToRemove = [];
      this.scene.traverse((child) => {
        if (
          child.type !== "Scene" &&
          !child.isLight &&
          !child.isAmbientLight &&
          !child.isDirectionalLight &&
          !child.isHemisphereLight
        ) {
          objectsToRemove.push(child);
        }
      });

      objectsToRemove.forEach((obj) => {
        if (obj.parent) {
          obj.parent.remove(obj);
        }
        if (obj.geometry) obj.geometry.dispose();
        if (obj.material) {
          if (Array.isArray(obj.material)) {
            obj.material.forEach((mat) => {
              if (mat.map) mat.map.dispose();
              if (mat.normalMap) mat.normalMap.dispose();
              if (mat.roughnessMap) mat.roughnessMap.dispose();
              if (mat.metalnessMap) mat.metalnessMap.dispose();
              mat.dispose();
            });
          } else {
            if (obj.material.map) obj.material.map.dispose();
            if (obj.material.normalMap) obj.material.normalMap.dispose();
            if (obj.material.roughnessMap) obj.material.roughnessMap.dispose();
            if (obj.material.metalnessMap) obj.material.metalnessMap.dispose();
            obj.material.dispose();
          }
        }
      });

      // Reset model reference
      this.model = null;

      // Force renderer clear
      if (this.renderer) {
        this.renderer.clear();
      }

      const loader = new GLTFLoader();
      loader.load(
        this.glbModelUrl,
        (gltf) => {
          this.model = gltf.scene;

          this.model.traverse((child) => {
            if (child.isMesh) {
              child.castShadow = true;
              child.receiveShadow = true;

              if (child.material) {
                if (Array.isArray(child.material)) {
                  child.material.forEach((mat) => (mat.needsUpdate = true));
                } else {
                  child.material.needsUpdate = true;
                }
              }
            }
          });

          this.modelBoundingBox = new THREE.Box3().setFromObject(this.model);
          this.modelSize = this.modelBoundingBox.getSize(new THREE.Vector3());
          this.modelCenter = this.modelBoundingBox.getCenter(
            new THREE.Vector3()
          );

          const maxDim = Math.max(
            this.modelSize.x,
            this.modelSize.y,
            this.modelSize.z
          );
          const desiredSize = 3;
          const scaleFactor = desiredSize / maxDim;
          this.model.scale.setScalar(scaleFactor);

          this.modelBoundingBox = new THREE.Box3().setFromObject(this.model);
          this.modelSize = this.modelBoundingBox.getSize(new THREE.Vector3());
          this.modelCenter = this.modelBoundingBox.getCenter(
            new THREE.Vector3()
          );

          this.model.position.sub(this.modelCenter);
          this.model.position.y = -this.modelBoundingBox.min.y;
          this.model.rotation.set(0, 0, 0);

          this.scene.add(this.model);
          this.createGroundPlane();
          this.fitCameraToModel();

          this.loading = false;
          this.modelLoaded = true;
        },
        (progress) => {
          console.log(
            "Loading progress:",
            (progress.loaded / progress.total) * 100 + "%"
          );
        },
        (error) => {
          console.error("Failed to load model", error);
          this.loading = false;
          this.modelLoaded = false;
        }
      );
    },

    createGroundPlane() {
      const groundGeometry = new THREE.PlaneGeometry(20, 20);
      const groundMaterial = new THREE.MeshLambertMaterial({
        color: 0xffffff,
        transparent: true,
        opacity: 0.1,
      });

      const groundPlane = new THREE.Mesh(groundGeometry, groundMaterial);
      groundPlane.rotation.x = -Math.PI / 2;
      groundPlane.position.y = -0.01;
      groundPlane.receiveShadow = true;
      this.scene.add(groundPlane);

      const gridHelper = new THREE.GridHelper(10, 20, 0xcccccc, 0xe0e0e0);
      gridHelper.position.y = 0;
      this.scene.add(gridHelper);
    },

    fitCameraToModel() {
      if (!this.model || !this.modelSize) return;

      const maxDim = Math.max(
        this.modelSize.x,
        this.modelSize.y,
        this.modelSize.z
      );
      const fov = this.camera.fov * (Math.PI / 180);
      const fitHeightDistance = maxDim / (2 * Math.tan(fov / 2));
      const fitWidthDistance = fitHeightDistance / this.camera.aspect;
      const distance = Math.max(fitHeightDistance, fitWidthDistance) * 2;

      this.camera.position.set(distance * -0.4, distance * 0.5, distance * 0.7);
      this.controls.target.copy(
        new THREE.Vector3(0, this.modelSize.y * 0.3, 0)
      );
      this.controls.update();
    },

    animate() {
      this.animationId = requestAnimationFrame(this.animate);

      if (this.controls) {
        this.controls.update();
      }

      if (this.renderer && this.scene && this.camera) {
        this.renderer.autoClear = false;
        this.renderer.clear();
        this.renderer.render(this.backgroundScene, this.backgroundCamera);
        this.renderer.render(this.scene, this.camera);
      }
    },

    onWindowResize() {
      if (!this.$refs.canvasContainer || !this.renderer || !this.camera) return;

      const container = this.$refs.canvasContainer;
      const width = container.clientWidth;
      const height = container.clientHeight;

      this.camera.aspect = width / height;
      this.camera.updateProjectionMatrix();
      this.renderer.setSize(width, height);
    },
  },
};
</script>
<style scoped>
#canvas-container {
  position: relative;
  width: 100%;
  height: 100%;
  min-height: 500px;
  background-color: #f3f2f7;
  overflow: hidden;
}

#viewer {
  width: 100%;
  height: 100%;
  background: #f3f2f7;
}

#viewer canvas {
  cursor: grab;
  width: 100% !important;
  height: 100% !important;
}

#viewer canvas:active {
  cursor: grabbing;
}

/* Loading Screen Overlay */
.scanning-loading-overlay {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: 10;
  overflow: hidden;
}

.loading-screen {
  width: 100%;
  height: 100%;
  background: linear-gradient(135deg, #f3f2f7 0%, #e9ecef 50%, #f3f2f7 100%);
  display: flex;
  align-items: center;
  justify-content: center;
}

.wave-overlay {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(
    to left,
    rgba(0, 102, 255, 1) 0%,
    rgba(0, 102, 255, 0.4) 20%,
    rgba(0, 102, 255, 0.3) 30%,
    rgba(0, 102, 255, 0.2) 35%,
    rgba(0, 102, 255, 0.15) 40%,
    rgba(0, 102, 255, 0.1) 50%,
    rgba(0, 102, 255, 0) 100%
  );
  animation: moveWave 3s linear infinite;
}

.loading-text {
  position: relative;
  color: #333;
  text-align: center;
  background: rgba(255, 255, 255, 0.9);
  padding: 25px 35px;
  border-radius: 15px;
  backdrop-filter: blur(10px);
  border: 2px solid rgba(0, 102, 255, 0.2);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1);
}

.process-text {
  font-size: 20px;
  font-weight: 600;
  letter-spacing: 1px;
  color: #495057;
}

/* No Model State Overlay */
.no-model-overlay {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  display: flex;
  align-items: flex-end;
  justify-content: flex-end;
  z-index: 5;
}

/* Model Loading State */
#loading {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  background: rgba(255, 255, 255, 0.95);
  color: #333;
  padding: 20px 30px;
  border-radius: 10px;
  font-size: 16px;
  z-index: 10;
  border: 2px solid #007acc;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.1);
}

/* Animations */
@keyframes moveWave {
  0% {
    transform: translateX(-100%);
  }
  100% {
    transform: translateX(100%);
  }
}

/* Responsive */
@media (max-width: 768px) {
  #canvas-container {
    height: 50vh;
    min-height: 300px;
  }

  .process-text {
    font-size: 16px;
  }

  .loading-text {
    padding: 20px 25px;
  }
}

@media (max-width: 480px) {
  #canvas-container {
    height: 40vh;
    min-height: 250px;
  }

  .process-text {
    font-size: 14px;
  }

  .loading-text {
    padding: 15px 20px;
  }
}
</style>
